 67→const StoryBrowser = () => {
 68→    const navigate = useNavigate();
 69→    const { session } = useAuth();
 70→    const token = session?.access_token;
 71→    const [searchParams, setSearchParams] = useSearchParams();
 72→    const statusFilter = searchParams.get('status') || null;
 73→
 74→    const {
 75→        data,
 76→        isLoading,
 77→        hasNextPage,
 78→        fetchNextPage,
 79→        isFetchingNextPage,
 80→    } = useInfiniteQuery({
 81→        queryKey: ['storiesBrowse', statusFilter],
 82→        queryFn: ({ pageParam = null }) => getStories(12, pageParam, statusFilter, null, token),
 83→        getNextPageParam: (lastPage) => {
 84→            if (!lastPage?.hasMore || !lastPage.data?.length) return undefined;
 85→            return lastPage.data[lastPage.data.length - 1].created_at;
 86→        },
 87→        initialPageParam: null,
 88→        refetchOnWindowFocus: false,
 89→    });
 90→
 91→    const stories = data?.pages?.flatMap(p => p.data) || [];
 92→
 93→    return (
 94→        <div className="story-browser">
 95→            <div className="story-browser-header">
 96→                <h2 className="story-browser-title">Stories</h2>
 97→                {session && (
 98→                    <div className="story-browser-header-actions">
 99→                        <button
100→                            className="story-browser-my-btn"
101→                            onClick={() => navigate('/home/stories/dashboard')}
102→                        >
103→                            My Stories
104→                        </button>
105→                        <button
106→                            className="story-browser-new-btn"
107→                            onClick={() => navigate('/home/stories/new')}
108→                        >
109→                            + Write
110→                        </button>
111→                    </div>
112→                )}
113→            </div>
114→
115→            <div className="story-browser-filters">
116→                {STATUS_FILTERS.map(f => (
117→                    <button
118→                        key={f.label}
119→                        className={`story-filter-btn ${statusFilter === f.value ? 'story-filter-btn-active' : ''}`}
120→                        onClick={() => {
121→                            if (f.value) {
122→                                setSearchParams({ status: f.value });
123→                            } else {
124→                                setSearchParams({});
125→                            }
126→                        }}
127→                    >
128→                        {f.label}
129→                    </button>
130→                ))}
131→            </div>
132→
133→            {isLoading ? (
134→                <div className="story-browser-loading">
135→                    <BeatLoader size={10} color="var(--text-muted)" />
136→                </div>
137→            ) : stories.length === 0 ? (
138→                <div className="story-browser-empty">
139→                    <p>No stories found.</p>
140→                </div>
141→            ) : (
142→                <>
143→                    <div className="story-browser-grid">
144→                        {stories.map(story => (
145→                            <StoryCard
146→                                key={story.id}
147→                                story={story}
148→                                onClick={() => navigate(`/home/stories/${story.id}`)}
149→                            />
150→                        ))}
151→                    </div>
152→                    {hasNextPage && (
153→                        <div className="story-browser-load-more">
154→                            <button
155→                                className="story-browser-load-more-btn"
156→                                onClick={() => fetchNextPage()}
157→                                disabled={isFetchingNextPage}
158→                            >
159→                                {isFetchingNextPage ? (
160→                                    <BeatLoader size={8} color="var(--text-secondary)" />
161→                                ) : (
162→                                    'Load more'
163→                                )}
164→                            </button>
165→                        </div>
166→                    )}
167→                </>
168→            )}
169→        </div>
170→    );
171→};
172→
173→export default StoryBrowser;
